-- OpenResty Session Management Module
-- Requires ngx module for luarocks. You can install it via `luarocks install ngx` command in your terminal or CMD.
local ngx = require("ngx")

-- Get the session cookie
local session_cookie = ngx.req.get_cookie('session')
if not session_cookie then 
   return ngx.exit(401, 'No Session ID Found in Cookies!')
